using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using verii_metivon_api.Modules.Procurement.Domain.Entities;
namespace verii_metivon_api.Modules.Procurement.Infrastructure.Persistence.Configurations;
public sealed class PurchaseOrderConfiguration:IEntityTypeConfiguration<PurchaseOrder>{public void Configure(EntityTypeBuilder<PurchaseOrder>b){b.ToTable("RII_PURCHASE_ORDERS");b.HasIndex(x=>x.OrderNumber).IsUnique();b.Property(x=>x.OrderNumber).HasMaxLength(40).IsRequired();b.Property(x=>x.ExchangeRate).HasPrecision(18,8);b.Property(x=>x.Subtotal).HasPrecision(24,8);b.Property(x=>x.DiscountTotal).HasPrecision(24,8);b.Property(x=>x.TaxTotal).HasPrecision(24,8);b.Property(x=>x.GrandTotal).HasPrecision(24,8);b.HasOne(x=>x.Supplier).WithMany().HasForeignKey(x=>x.SupplierId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.Warehouse).WithMany().HasForeignKey(x=>x.WarehouseId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class PurchaseOrderLineConfiguration:IEntityTypeConfiguration<PurchaseOrderLine>{public void Configure(EntityTypeBuilder<PurchaseOrderLine>b){b.ToTable("RII_PURCHASE_ORDER_LINES");b.HasIndex(x=>new{x.PurchaseOrderId,x.LineNumber}).IsUnique();foreach(var p in new[]{nameof(PurchaseOrderLine.OrderedQuantity),nameof(PurchaseOrderLine.ReceivedQuantity),nameof(PurchaseOrderLine.InvoicedQuantity),nameof(PurchaseOrderLine.UnitPrice),nameof(PurchaseOrderLine.DiscountAmount),nameof(PurchaseOrderLine.TaxAmount),nameof(PurchaseOrderLine.LineTotal)})b.Property(p).HasPrecision(24,8);b.Property(x=>x.DiscountRate).HasPrecision(9,6);b.Property(x=>x.TaxRate).HasPrecision(9,6);b.Property(x=>x.OverDeliveryTolerance).HasPrecision(9,6);b.Property(x=>x.UnderDeliveryTolerance).HasPrecision(9,6);b.HasOne(x=>x.PurchaseOrder).WithMany(x=>x.Lines).HasForeignKey(x=>x.PurchaseOrderId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class ProcurementParameterSettingsConfiguration:IEntityTypeConfiguration<ProcurementParameterSettings>{public void Configure(EntityTypeBuilder<ProcurementParameterSettings>b){b.ToTable("RII_PROCUREMENT_PARAMETERS",t=>{t.HasCheckConstraint("CK_RII_PROCUREMENT_PARAMETERS_LEAD_TIME","[DefaultLeadTimeDays] >= 0 AND [DefaultLeadTimeDays] <= 3650");t.HasCheckConstraint("CK_RII_PROCUREMENT_PARAMETERS_MAX_LINES","[MaximumLinesPerOrder] >= 1 AND [MaximumLinesPerOrder] <= 10000");t.HasCheckConstraint("CK_RII_PROCUREMENT_PARAMETERS_TOLERANCE","[DefaultOverDeliveryTolerancePercent] >= 0 AND [DefaultOverDeliveryTolerancePercent] <= 100 AND [DefaultUnderDeliveryTolerancePercent] >= 0 AND [DefaultUnderDeliveryTolerancePercent] <= 100");t.HasCheckConstraint("CK_RII_PROCUREMENT_PARAMETERS_AMOUNTS","[MinimumOrderAmount] >= 0 AND [MaximumOrderAmount] >= 0 AND ([MaximumOrderAmount] = 0 OR [MaximumOrderAmount] >= [MinimumOrderAmount])");t.HasCheckConstraint("CK_RII_PROCUREMENT_PARAMETERS_DISCOUNT","[MaximumDiscountPercent] >= 0 AND [MaximumDiscountPercent] <= 100");});b.HasKey(x=>x.Id);b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.BranchId,x.WarehouseId}).IsUnique().HasFilter("[IsDeleted] = 0");b.Property(x=>x.DefaultOverDeliveryTolerancePercent).HasPrecision(9,6);b.Property(x=>x.DefaultUnderDeliveryTolerancePercent).HasPrecision(9,6);b.Property(x=>x.MinimumOrderAmount).HasPrecision(24,8);b.Property(x=>x.MaximumOrderAmount).HasPrecision(24,8);b.Property(x=>x.MaximumDiscountPercent).HasPrecision(9,6);b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.Warehouse).WithMany().HasForeignKey(x=>x.WarehouseId).OnDelete(DeleteBehavior.Restrict);}}
